  1→import { useCallback, useEffect } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { TOOLS } from '@/editor/tools';
  6→import { detectRooms } from '@/geometry/roomDetection';
  7→import { createRoom } from '@/domain/models';
  8→import { isTypingTarget } from '@/utils/keyboard';
  9→import {
 10→  NewIcon, SaveIcon, LoadIcon, UndoIcon, RedoIcon,
 11→  CopyIcon, CutIcon, PasteIcon,
 12→  SelectIcon, DimensionIcon, WallIcon, BeamIcon, StairIcon,
 13→  TrussDrawIcon,
 14→  SectionCutIcon, SlabIcon, RoomIcon, DoorIcon, WindowIcon,
 15→  ColumnIcon, LandingIcon, RailingIcon,
 16→  ParapetIcon, DrainIcon, OpeningIcon,
 17→  KitchenTopIcon, ToiletIcon, LavatoryIcon, TableIcon, TVIcon, SofaIcon, BedIcon,
 18→  GridIcon, SnapIcon, DetectRoomsIcon,
 19→  SidebarIcon, PropertiesIcon,
 20→} from './ToolbarIcons';
 21→import { FIXTURE_TYPES } from '@/editor/tools';
 22→import styles from './Toolbar.module.css';
 23→
 24→const viewModes = [
 25→  { key: 'plan', label: 'Plan', viewMode: 'plan' },
 26→  { key: 'front', label: 'Front', viewMode: 'elevation_front' },
 27→  { key: 'rear', label: 'Rear', viewMode: 'elevation_rear' },
 28→  { key: 'left', label: 'Left', viewMode: 'elevation_left' },
 29→  { key: 'right', label: 'Right', viewMode: 'elevation_right' },
 30→  { key: 'section', label: 'Section', viewMode: 'section_view' },
 31→];
 32→
 33→const toolItems = [
 34→  { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
 35→  { tool: TOOLS.DIMENSION, label: 'Dimension', shortcut: 'M', Icon: DimensionIcon },
 36→  { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W', Icon: WallIcon },
 37→  { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B', Icon: BeamIcon },
 38→  { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T', Icon: StairIcon },
 39→  { tool: TOOLS.SECTION, label: 'Section Cut', shortcut: 'Q', Icon: SectionCutIcon },
 40→  { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S', Icon: SlabIcon },
 41→  { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R', Icon: RoomIcon },
 42→  { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', Icon: DoorIcon },
 43→  { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N', Icon: WindowIcon },
 44→  { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C', Icon: ColumnIcon },
 45→  { tool: TOOLS.LANDING, label: 'Landing', shortcut: 'L', Icon: LandingIcon },
 46→  { tool: TOOLS.RAILING, label: 'Railing', shortcut: 'H', Icon: RailingIcon },
 47→];
 48→
 49→export default function Toolbar({
 50→  onNew,
 51→  onSave,
 52→  onLoad,
 53→  isSidebarCollapsed,
 54→  isPropertiesCollapsed,
 55→  onToggleSidebar,
 56→  onToggleProperties,
 57→}) {
 58→  const {
 59→    activeTool,
 60→    showGrid,
 61→    snapEnabled,
 62→    activeFloorId,
 63→    viewMode,
 64→    workspaceMode,
 65→    modelTarget,
 66→    toolState,
 67→    activePhaseId,
 68→    selectedId,
 69→    selectedType,
 70→    dispatch: editorDispatch,
 71→  } = useEditor();
 72→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 73→  const {
 74→    canCopySelection,
 75→    canPaste,
 76→    copySelection,
 77→    cutSelection,
 78→    beginPaste,
 79→  } = usePlanClipboardController();
 80→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'floor';
 81→  const isRoofPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'roof';
 82→  const isTrussPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'truss';
 83→
 84→  const fixtureItems = [
 85→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 86→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 87→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 88→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 89→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 90→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 91→    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 92→  ];
 93→
 94→  const setTool = (tool) => {
 95→    editorDispatch({ type: 'SET_TOOL', tool });
 96→
 97→    if (tool !== TOOLS.TRUSS_DRAW || modelTarget !== 'truss') return;
 98→
 99→    const targetTrussSystem = selectedType === 'trussSystem'
100→      ? (project.trussSystems || []).find((entry) => entry.id === selectedId) || null
101→      : selectedType === 'trussInstance'
102→        ? (project.trussSystems || []).find((entry) => (
103→            (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
104→          )) || null
105→        : null;
106→    const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
107→      ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
108→      : null;
109→    const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
110→      ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
111→      : null;
112→
113→    editorDispatch({
114→      type: 'UPDATE_TOOL_STATE',
115→      payload: {
116→        targetTrussSystemId: targetTrussSystem?.id || null,
117→        trussTypeId: selectedTrussInstance?.trussTypeId
118→          || lastSystemInstance?.trussTypeId
119→          || null,
120→        trussMaterial: selectedTrussInstance?.material
121→          || lastSystemInstance?.material
122→          || null,
123→      },
124→    });
125→  };
126→  const roofToolItems = [
127→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
128→    { tool: TOOLS.ROOF_PARAPET, label: 'Parapet', shortcut: 'P', Icon: ParapetIcon },
129→    { tool: TOOLS.ROOF_DRAIN, label: 'Drain', shortcut: 'G', Icon: DrainIcon },
130→    { tool: TOOLS.ROOF_OPENING, label: 'Opening', shortcut: 'O', Icon: OpeningIcon },
131→  ];
132→  const trussToolItems = [
133→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
134→    { tool: TOOLS.TRUSS_DRAW, label: 'Draw Truss', shortcut: 'T', Icon: TrussDrawIcon },
135→  ];
136→  const currentViewModes = modelTarget === 'truss'
137→    ? [
138→        { key: 'plan', label: 'Plan', viewMode: 'plan' },
139→        { key: 'detail', label: 'Detail', viewMode: 'truss_detail' },
140→        { key: 'section', label: 'Section', viewMode: 'section_view' },
141→      ]
142→    : viewModes;
143→
144→  const handleUndo = useCallback(() => {
145→    if (!canUndo) return;
146→    dispatch({ type: 'UNDO' });
147→    editorDispatch({ type: 'DESELECT' });
148→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
149→  }, [canUndo, dispatch, editorDispatch]);
150→
151→  const handleRedo = useCallback(() => {
152→    if (!canRedo) return;
153→    dispatch({ type: 'REDO' });
154→    editorDispatch({ type: 'DESELECT' });
155→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
156→  }, [canRedo, dispatch, editorDispatch]);
157→
158→  const handleDetectRooms = () => {
159→    const floor = project.floors.find(f => f.id === activeFloorId);
160→    if (!floor || floor.walls.length < 3) {
161→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
162→      return;
163→    }
164→    const detected = detectRooms(floor.walls, floor.columns || []);
165→    const rooms = detected.map((d, i) => {
166→      const room = createRoom(`Room ${i + 1}`, d.points);
167→      room.phaseId = activePhaseId || null;
168→      return room;
169→    });
170→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
171→    editorDispatch({ type: 'DESELECT' });
172→    editorDispatch({
173→      type: 'SET_STATUS_MESSAGE',
174→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
175→    });
176→  };
177→
178→  useEffect(() => {
179→    const handleKeyDown = (e) => {
180→      if (!(e.ctrlKey || e.metaKey)) return;
181→      if (isTypingTarget(e.target)) return;
182→
183→      const key = e.key.toLowerCase();
184→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
185→      const isUndo = key === 'z' && !e.shiftKey;
186→      if (!isUndo && !isRedo) return;
187→
188→      e.preventDefault();
189→      if (isRedo) {
190→        handleRedo();
191→        return;
192→      }
193→      handleUndo();
194→    };
195→
196→    window.addEventListener('keydown', handleKeyDown);
197→    return () => window.removeEventListener('keydown', handleKeyDown);
198→  }, [handleRedo, handleUndo]);
199→
200→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
201→    currentViewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
202→
203→  return (
204→    <div className={styles.toolbar}>
205→      {/* File & clipboard actions */}
206→      <div className={styles.group}>
207→        <button className={styles.btn} onClick={onNew} title="New Project">
208→          <NewIcon className={styles.icon} />
209→        </button>
210→        <button
211→          className={styles.btn}
212→          onClick={handleUndo}
213→          disabled={!canUndo}
214→          title="Undo (Ctrl+Z)"
215→          aria-label="Undo"
216→        >
217→          <UndoIcon className={styles.icon} />
218→        </button>
219→        <button
220→          className={styles.btn}
221→          onClick={handleRedo}
222→          disabled={!canRedo}
223→          title="Redo (Ctrl+Shift+Z)"
224→          aria-label="Redo"
225→        >
226→          <RedoIcon className={styles.icon} />
227→        </button>
228→        <button
229→          className={styles.saveBtn}
230→          onClick={onSave}
231→          title="Save (Ctrl+S)"
232→          data-dirty={isDirty}
233→        >
234→          <SaveIcon className={styles.icon} />
235→        </button>
236→        <div className={styles.divider} />
237→        <button className={styles.btn} onClick={onLoad} title="Load Project">
238→          <LoadIcon className={styles.icon} />
239→        </button>
240→        <button
241→          className={styles.btn}
242→          onClick={copySelection}
243→          disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
244→          title="Copy (Ctrl+C)"
245→        >
246→          <CopyIcon className={styles.icon} />
247→        </button>
248→        <button
249→          className={styles.btn}
250→          onClick={cutSelection}
251→          disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
252→          title="Cut (Ctrl+X)"
253→        >
254→          <CutIcon className={styles.icon} />
255→        </button>
256→        <button
257→          className={styles.btn}
258→          onClick={() => beginPaste()}
259→          disabled={!canPaste || modelTarget !== 'floor' || workspaceMode !== 'model'}
260→          title="Paste (Ctrl+V)"
261→        >
262→          <PasteIcon className={styles.icon} />
263→        </button>
264→      </div>
265→
266→      <div className={styles.segmentedGroup}>
267→        <button
268→          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
269→          onClick={() => {
270→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
271→            if (viewMode === 'truss_detail') {
272→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
273→            }
274→          }}
275→          title="Floor Editing"
276→        >
277→          Floor
278→        </button>
279→        <button
280→          className={workspaceMode === 'model' && modelTarget === 'roof' ? styles.segmentedBtnActive : styles.segmentedBtn}
281→          onClick={() => {
282→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
283→            if (viewMode === 'truss_detail') {
284→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
285→            }
286→          }}
287→          title="Roof Editing"
288→        >
289→          Roof
290→        </button>
291→        <button
292→          className={workspaceMode === 'model' && modelTarget === 'truss' ? styles.segmentedBtnActive : styles.segmentedBtn}
293→          onClick={() => {
294→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
295→            if (viewMode !== 'plan' && viewMode !== 'section_view' && viewMode !== 'truss_detail') {
296→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
297→            }
298→          }}
299→          title="Truss Editing"
300→        >
301→          Truss
302→        </button>
303→        <button
304→          className={workspaceMode === 'sheet' ? styles.segmentedBtnActive : styles.segmentedBtn}
305→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
306→          title="Sheet Workspace"
307→        >
308→          Sheets
309→        </button>
310→      </div>
311→
312→      {/* View mode segmented control */}
313→      <div className={styles.segmentedGroup}>
314→        {currentViewModes.map(({ key, label, viewMode: vm }) => (
315→          <button
316→            key={key}
317→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
318→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
319→            title={`${label} View`}
320→          >
321→            {label}
322→          </button>
323→        ))}
324→      </div>
325→
326→      {/* Tool palette - inline row of 12 icons */}
327→      <div className={styles.toolPalette}>
328→        <span className={styles.groupLabel}>Tools</span>
329→        {(modelTarget === 'roof' ? roofToolItems : (modelTarget === 'truss' ? trussToolItems : toolItems)).map(({ tool, label, shortcut, Icon }) => (
330→          <button
331→            key={tool}
332→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
333→            onClick={() => setTool(tool)}
334→            disabled={modelTarget === 'roof' ? !isRoofPlanView : (modelTarget === 'truss' ? !isTrussPlanView : !isPlanView)}
335→            title={`${label} (${shortcut})`}
336→            aria-label={label}
337→          >
338→            <Icon className={styles.toolPaletteIcon} />
339→          </button>
340→        ))}
341→      </div>
342→
343→      {/* Fixtures palette */}
344→      <div className={styles.fixturePalette}>
345→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
346→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
347→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
348→          return (
349→            <button
350→              key={fixtureType}
351→              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
352→              onClick={() => {
353→                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
354→                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
355→              }}
356→              disabled={!isPlanView}
357→              title={`${label} (F)`}
358→              aria-label={label}
359→            >
360→              <Icon className={styles.toolPaletteIcon} />
361→            </button>
362→          );
363→        })}
364→      </div>
365→
366→      {/* Panel toggles & utility toggles */}
367→      <div className={styles.group}>
368→        <span className={styles.groupLabel}>Panels</span>
369→        <button
370→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
371→          onClick={onToggleSidebar}
372→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
373→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
374→        >
375→          <SidebarIcon className={styles.icon} />
376→        </button>
377→        <button
378→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
379→          onClick={onToggleProperties}
380→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
381→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
382→        >
383→          <PropertiesIcon className={styles.icon} />
384→        </button>
385→        <div className={styles.divider} />
386→        <span className={styles.groupLabel}>Display</span>
387→        <button
388→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
389→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
390→          title="Toggle Grid"
391→          aria-label="Toggle Grid"
392→        >
393→          <GridIcon className={styles.icon} />
394→        </button>
395→        <button
396→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
397→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
398→          title="Toggle Snap"
399→          aria-label="Toggle Snap"
400→        >
401→          <SnapIcon className={styles.icon} />
402→        </button>
403→        <button
404→          className={styles.btn}
405→          onClick={handleDetectRooms}
406→          title="Auto-detect Rooms"
407→          disabled={!isPlanView}
408→          aria-label="Auto-detect Rooms"
409→        >
410→          <DetectRoomsIcon className={styles.icon} />
411→        </button>
412→      </div>
413→
414→      <div className={styles.spacer} />
415→    </div>
416→  );
417→}
418→

  1→const p = { fill: 'none', stroke: 'currentColor', strokeWidth: 1.5, strokeLinecap: 'round', strokeLinejoin: 'round' };
  2→const box = 'icon';
  3→
  4→function I({ children, className }) {
  5→  return (
  6→    <svg viewBox="0 0 20 20" aria-hidden="true" className={className || box}>
  7→      {children}
  8→    </svg>
  9→  );
 10→}
 11→
 12→export function NewIcon(props) {
 13→  return <I {...props}><path d="M6 3h5l4 4v10a1 1 0 0 1-1 1H6a1 1 0 0 1-1-1V4a1 1 0 0 1 1-1z" {...p} /><path d="M11 3v4h4" {...p} /></I>;
 14→}
 15→
 16→export function SaveIcon(props) {
 17→  return <I {...props}><path d="M5 3h8l3 3v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2z" {...p} /><path d="M7 3v4h5V3" {...p} /><rect x="6" y="11" width="8" height="5" rx="0.5" {...p} /></I>;
 18→}
 19→
 20→export function LoadIcon(props) {
 21→  return <I {...props}><path d="M3 7V5a2 2 0 0 1 2-2h4l2 2h4a2 2 0 0 1 2 2v1" {...p} /><path d="M3 7h14a1 1 0 0 1 1 1l-1.5 8a1 1 0 0 1-1 .8H4.5a1 1 0 0 1-1-.8L2 8a1 1 0 0 1 1-1z" {...p} /></I>;
 22→}
 23→
 24→export function UndoIcon(props) {
 25→  return <I {...props}><path d="M7 5 3.5 8.5 7 12" {...p} /><path d="M4 8.5h6.5A4.5 4.5 0 0 1 15 13v1" {...p} /></I>;
 26→}
 27→
 28→export function RedoIcon(props) {
 29→  return <I {...props}><path d="M13 5l3.5 3.5L13 12" {...p} /><path d="M16 8.5H9.5A4.5 4.5 0 0 0 5 13v1" {...p} /></I>;
 30→}
 31→
 32→export function CopyIcon(props) {
 33→  return <I {...props}><rect x="7" y="7" width="9" height="10" rx="1" {...p} /><path d="M4 13V5a1 1 0 0 1 1-1h7" {...p} /></I>;
 34→}
 35→
 36→export function CutIcon(props) {
 37→  return <I {...props}><circle cx="7" cy="15" r="2" {...p} /><circle cx="13" cy="15" r="2" {...p} /><path d="M8.5 13.5 14 4" {...p} /><path d="M11.5 13.5 6 4" {...p} /></I>;
 38→}
 39→
 40→export function PasteIcon(props) {
 41→  return <I {...props}><path d="M8 4H6a1 1 0 0 0-1 1v11a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1v-3" {...p} /><rect x="8" y="2" width="4" height="3" rx="0.5" {...p} /><rect x="9" y="7" width="8" height="6" rx="1" {...p} /></I>;
 42→}
 43→
 44→export function SelectIcon(props) {
 45→  return <I {...props}><path d="M5 3l2 14 3-5 5-3L5 3z" {...p} /></I>;
 46→}
 47→
 48→export function DimensionIcon(props) {
 49→  return <I {...props}><path d="M4 6v8" {...p} /><path d="M16 6v8" {...p} /><path d="M4 10h12" {...p} /><path d="M6 8.5 4 10l2 1.5" {...p} /><path d="M14 8.5l2 1.5-2 1.5" {...p} /></I>;
 50→}
 51→
 52→export function WallIcon(props) {
 53→  return <I {...props}><rect x="3" y="7" width="14" height="6" rx="0.5" {...p} /><path d="M7 7v6M13 7v6" {...p} strokeDasharray="2 2" /></I>;
 54→}
 55→
 56→export function BeamIcon(props) {
 57→  return <I {...props}><rect x="2" y="8" width="16" height="4" rx="0.5" {...p} /><circle cx="5" cy="10" r="1" fill="currentColor" stroke="none" /><circle cx="15" cy="10" r="1" fill="currentColor" stroke="none" /></I>;
 58→}
 59→
 60→export function TrussDrawIcon(props) {
 61→  return (
 62→    <I {...props}>
 63→      <line x1="3" y1="13" x2="17" y2="13" {...p} />
 64→      <path d="M4 13 10 6l6 7" {...p} />
 65→      <path d="M6.5 10h7" {...p} strokeDasharray="2 2" />
 66→      <circle cx="4" cy="13" r="1" fill="currentColor" stroke="none" />
 67→      <circle cx="16" cy="13" r="1" fill="currentColor" stroke="none" />
 68→    </I>
 69→  );
 70→}
 71→
 72→export function StairIcon(props) {
 73→  return <I {...props}><path d="M4 16h3v-3h3v-3h3v-3h3V4" {...p} /></I>;
 74→}
 75→
 76→export function SectionCutIcon(props) {
 77→  return <I {...props}><path d="M10 3v14" {...p} strokeDasharray="3 2" /><path d="M7 5l3-2 3 2" {...p} /><path d="M7 15l3 2 3-2" {...p} /></I>;
 78→}
 79→
 80→export function SlabIcon(props) {
 81→  return <I {...props}><path d="M3 12l7-4 7 4-7 4-7-4z" {...p} /><path d="M3 12v2l7 4 7-4v-2" {...p} /></I>;
 82→}
 83→
 84→export function RoomIcon(props) {
 85→  return <I {...props}><rect x="4" y="4" width="12" height="12" rx="1" {...p} /><path d="M4 10h12" {...p} strokeDasharray="2 2" /><path d="M10 4v12" {...p} strokeDasharray="2 2" /></I>;
 86→}
