 53→export function RoofEmptyState({ project, dispatch, editorDispatch, activePhaseId = null }) {
 54→  const attachableTrussSystems = getAttachableRoofTrussSystems(project);
 55→  const [selectedTrussSystemId, setSelectedTrussSystemId] = useState(attachableTrussSystems[0]?.id || '');
 56→
 57→  useEffect(() => {
 58→    if (!attachableTrussSystems.some((entry) => entry.id === selectedTrussSystemId)) {
 59→      setSelectedTrussSystemId(attachableTrussSystems[0]?.id || '');
 60→    }
 61→  }, [attachableTrussSystems, selectedTrussSystemId]);
 62→
 63→  const selectedTrussSystem = attachableTrussSystems.find((entry) => entry.id === selectedTrussSystemId) || null;
 64→  const selectedRoofType = selectedTrussSystem
 65→    ? resolveTrussSystemRoofAttachmentType(selectedTrussSystem)
 66→    : null;
 67→  const handleCreate = () => {
 68→    const roofSystem = createRoofSystemForProject(project, {
 69→      phaseId: activePhaseId || null,
 70→      trussAttachmentId: selectedTrussSystemId || null,
 71→    });
 72→    if (!roofSystem) return;
 73→    dispatch({ type: 'ROOF_CREATE', roofSystem });
 74→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
 75→    editorDispatch({ type: 'SELECT_OBJECT', id: roofSystem.id, objectType: 'roofSystem' });
 76→  };
 77→
 78→  return (
 79→    <div>
 80→      <div className={styles.title}>Roof</div>
 81→      <div className={styles.drawingHint}>
 82→        Roof creation is truss-driven. Add a roof-ready truss system first, then create the roof from that truss so the roof outline, shape, pitch family, and support elevation all follow the truss system.
 83→      </div>
 84→      {!attachableTrussSystems.length ? (
 85→        <div className={styles.drawingHint}>
 86→          No roof-ready truss system is available. Create trusses first, and keep each truss system on one supported roof shape before adding a roof.
 87→        </div>
 88→      ) : (
 89→        <>
 90→          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
 91→            <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Truss</label>
 92→            <select
