 48→function resolveSupportBeamLabel(project, floorId, beamId) {
 49→  if (!beamId) return 'None';
 50→
 51→  const floor = (project?.floors || []).find((entry) => entry.id === floorId) || null;
 52→  const beam = (floor?.beams || []).find((entry) => entry.id === beamId) || null;
 53→  if (!floor || !beam) {
 54→    return 'Missing beam';
 55→  }
 56→  return getBeamDisplayLabel(beam, floor.columns || []);
 57→}
