 66→function PlanViewportContent({ floor }) {
 67→  return (
 68→    <>
 69→      {(floor.slabs || []).map(slab => (
 70→        <SlabRenderer key={slab.id} slab={slab} selectedId={null} />
 71→      ))}
 72→      <RoomRenderer rooms={floor.rooms} selectedId={null} interactive={false} />
 73→      <WallRenderer walls={floor.walls} columns={floor.columns || []} />
 74→      <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
