217→  if (source.kind === 'roof_elevation') {
218→    return (
219→      <ElevationSceneLayer
220→        scene={source.scene}
221→        annotationScene={null}
222→        showTitle={false}
223→      />
224→    );
225→  }
226→
227→  return null;
228→}
