 85→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 86→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 87→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
