 95→    trusses: false,
 96→    sheets: false,
 97→    phases: false,
 98→    slabs: false,
 99→    walls: false,
100→    annotations: false,
101→    beams: false,
102→    stairs: false,
103→    landings: false,
104→    doors: false,
105→    windows: false,
106→    columns: false,
107→    rooms: false,
