228→    workspaceMode: 'model',
229→    viewport: { ...modelViewport },
230→    modelViewport,
231→    sheetViewport,
232→    showGrid: true,
233→    snapEnabled: true,
234→    viewMode: 'plan',
235→    activeFloorId,
236→    activeSheetId: null,
237→    activeSectionCutId: null,
238→    statusMessage: null,
239→    regionSelection: null,
