174→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
175→    });
176→  };
177→
178→  useEffect(() => {
179→    const handleKeyDown = (e) => {
180→      if (!(e.ctrlKey || e.metaKey)) return;
181→      if (isTypingTarget(e.target)) return;
182→
183→      const key = e.key.toLowerCase();
184→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
185→      const isUndo = key === 'z' && !e.shiftKey;
186→      if (!isUndo && !isRedo) return;
187→
188→      e.preventDefault();
189→      if (isRedo) {
190→        handleRedo();
191→        return;
192→      }
193→      handleUndo();
194→    };
195→
196→    window.addEventListener('keydown', handleKeyDown);
197→    return () => window.removeEventListener('keydown', handleKeyDown);
198→  }, [handleRedo, handleUndo]);
199→
200→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
201→    currentViewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
202→
203→  return (
204→    <div className={styles.toolbar}>
205→      {/* File & clipboard actions */}
206→      <div className={styles.group}>
