215→          aria-label="Undo"
216→        >
217→          <UndoIcon className={styles.icon} />
218→        </button>
219→        <button
220→          className={styles.btn}
221→          onClick={handleRedo}
222→          disabled={!canRedo}
223→          title="Redo (Ctrl+Shift+Z)"
224→          aria-label="Redo"
225→        >
226→          <RedoIcon className={styles.icon} />
227→        </button>
228→        <button
229→          className={styles.saveBtn}
230→          onClick={onSave}
231→          title="Save (Ctrl+S)"
232→          data-dirty={isDirty}
233→        >
234→          <SaveIcon className={styles.icon} />
235→        </button>
236→        <div className={styles.divider} />
237→        <button className={styles.btn} onClick={onLoad} title="Load Project">
238→          <LoadIcon className={styles.icon} />
239→        </button>
240→        <button
241→          className={styles.btn}
242→          onClick={copySelection}
243→          disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
244→          title="Copy (Ctrl+C)"
245→        >
246→          <CopyIcon className={styles.icon} />
247→        </button>
248→        <button
249→          className={styles.btn}
250→          onClick={cutSelection}
251→          disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
252→          title="Cut (Ctrl+X)"
253→        >
254→          <CutIcon className={styles.icon} />
255→        </button>
256→        <button
257→          className={styles.btn}
258→          onClick={() => beginPaste()}
259→          disabled={!canPaste || modelTarget !== 'floor' || workspaceMode !== 'model'}
260→          title="Paste (Ctrl+V)"
261→        >
262→          <PasteIcon className={styles.icon} />
263→        </button>
264→      </div>
265→
266→      <div className={styles.segmentedGroup}>
267→        <button
268→          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
269→          onClick={() => {
270→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
271→            if (viewMode === 'truss_detail') {
272→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
273→            }
274→          }}
275→          title="Floor Editing"
276→        >
277→          Floor
278→        </button>
279→        <button
280→          className={workspaceMode === 'model' && modelTarget === 'roof' ? styles.segmentedBtnActive : styles.segmentedBtn}
281→          onClick={() => {
282→            editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
283→            if (viewMode === 'truss_detail') {
284→              editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
285→            }
286→          }}
287→          title="Roof Editing"
288→        >
289→          Roof
